with seed(ord,teks_code,rit_band,difficulty,stem,stem_image_svg,explanation,source_note,choices) as (values
(1,$code$4.11D.vi$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Choose the phrase that tells where: Priya waited ___ the gym.$stem$,NULL,$exp$Beside the gym is a prepositional phrase telling where.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"beside","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":1},{"label":"B","body":"often","is_correct":false,"misconception":"Confused an adverb or adjective with a prepositional phrase.","misconception_tag":"preposition_use","sort_order":2},{"label":"C","body":"carefully","is_correct":false,"misconception":"Confused an adverb or adjective with a prepositional phrase.","misconception_tag":"preposition_use","sort_order":3},{"label":"D","body":"happy","is_correct":false,"misconception":"Confused an adverb or adjective with a prepositional phrase.","misconception_tag":"preposition_use","sort_order":4}]$choices$::jsonb),
(2,$code$4.11D.vi$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which sentence uses a prepositional phrase correctly?$stem$,NULL,$exp$Inside the folder is a prepositional phrase.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"The note blue the folder is mine.","is_correct":false,"misconception":"Did not recognize a complete prepositional phrase.","misconception_tag":"preposition_use","sort_order":1},{"label":"B","body":"The note inside the folder is mine.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":2},{"label":"C","body":"The note carefully is mine.","is_correct":false,"misconception":"Did not recognize a complete prepositional phrase.","misconception_tag":"preposition_use","sort_order":3},{"label":"D","body":"The note because the folder is mine.","is_correct":false,"misconception":"Did not recognize a complete prepositional phrase.","misconception_tag":"preposition_use","sort_order":4}]$choices$::jsonb),
(3,$code$4.11D.vi$code$,'211_220'::map_rit_band,'hard'::map_difficulty,$stem$Which phrase completes the sentence best? The trail curved ___ the river.$stem$,NULL,$exp$Along the river shows direction and location.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"without","is_correct":false,"misconception":"Chose a preposition that does not fit the meaning.","misconception_tag":"preposition_use","sort_order":1},{"label":"B","body":"except","is_correct":false,"misconception":"Chose a preposition that does not fit the meaning.","misconception_tag":"preposition_use","sort_order":2},{"label":"C","body":"along","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":3},{"label":"D","body":"during","is_correct":false,"misconception":"Chose a preposition that does not fit the meaning.","misconception_tag":"preposition_use","sort_order":4}]$choices$::jsonb),
(4,$code$4.11D.vii$code$,'191_200'::map_rit_band,'easy'::map_difficulty,$stem$Choose the correct pronoun: Ava and I packed ___ lunches.$stem$,NULL,$exp$Our shows the lunches belong to Ava and me.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"us","is_correct":false,"misconception":"Chose the wrong pronoun type.","misconception_tag":"pronoun_mismatch","sort_order":1},{"label":"B","body":"we","is_correct":false,"misconception":"Chose the wrong pronoun type.","misconception_tag":"pronoun_mismatch","sort_order":2},{"label":"C","body":"ourselves","is_correct":false,"misconception":"Chose the wrong pronoun type.","misconception_tag":"pronoun_mismatch","sort_order":3},{"label":"D","body":"our","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":4}]$choices$::jsonb),
(5,$code$4.11D.vii$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Choose the correct pronoun: The teacher gave the forms to Maya and ___.$stem$,NULL,$exp$Use object pronoun me after to.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"me","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":1},{"label":"B","body":"I","is_correct":false,"misconception":"Used a subject or reflexive pronoun as an object.","misconception_tag":"pronoun_mismatch","sort_order":2},{"label":"C","body":"myself","is_correct":false,"misconception":"Used a subject or reflexive pronoun as an object.","misconception_tag":"pronoun_mismatch","sort_order":3},{"label":"D","body":"mine","is_correct":false,"misconception":"Used a subject or reflexive pronoun as an object.","misconception_tag":"pronoun_mismatch","sort_order":4}]$choices$::jsonb),
(6,$code$4.11D.vii$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which sentence uses a reflexive pronoun correctly?$stem$,NULL,$exp$Himself is the correct reflexive pronoun.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"Diego made the model his.","is_correct":false,"misconception":"Used a nonstandard or wrong pronoun form.","misconception_tag":"pronoun_mismatch","sort_order":1},{"label":"B","body":"Diego made the model himself.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":2},{"label":"C","body":"Diego made the model hisself.","is_correct":false,"misconception":"Used a nonstandard or wrong pronoun form.","misconception_tag":"pronoun_mismatch","sort_order":3},{"label":"D","body":"Diego made the model him.","is_correct":false,"misconception":"Used a nonstandard or wrong pronoun form.","misconception_tag":"pronoun_mismatch","sort_order":4}]$choices$::jsonb),
(7,$code$4.11D.vii$code$,'211_220'::map_rit_band,'hard'::map_difficulty,$stem$Which revision fixes the pronoun error?$stem$,NULL,$exp$She is a subject pronoun.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"Nia and hers will lead the game.","is_correct":false,"misconception":"Used an object or reflexive pronoun as a subject.","misconception_tag":"pronoun_mismatch","sort_order":1},{"label":"B","body":"Nia and herself will lead the game.","is_correct":false,"misconception":"Used an object or reflexive pronoun as a subject.","misconception_tag":"pronoun_mismatch","sort_order":2},{"label":"C","body":"Nia and she will lead the game.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":3},{"label":"D","body":"Nia and her will lead the game.","is_correct":false,"misconception":"Used an object or reflexive pronoun as a subject.","misconception_tag":"pronoun_mismatch","sort_order":4}]$choices$::jsonb),
(8,$code$4.11D.vii$code$,'221_230'::map_rit_band,'hard'::map_difficulty,$stem$Choose the sentence with a clear pronoun reference.$stem$,NULL,$exp$Repeating Zoe makes it clear who waved.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"When Zoe saw Hana, she waved.","is_correct":false,"misconception":"Used an unclear pronoun reference.","misconception_tag":"pronoun_mismatch","sort_order":1},{"label":"B","body":"Zoe saw Hana, and it waved.","is_correct":false,"misconception":"Used an unclear pronoun reference.","misconception_tag":"pronoun_mismatch","sort_order":2},{"label":"C","body":"She saw Zoe when Hana waved.","is_correct":false,"misconception":"Used an unclear pronoun reference.","misconception_tag":"pronoun_mismatch","sort_order":3},{"label":"D","body":"When Zoe saw Hana, Zoe waved.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":4}]$choices$::jsonb),
(9,$code$4.11D.viii$code$,'191_200'::map_rit_band,'easy'::map_difficulty,$stem$Choose the conjunction: I wanted to play, ___ it started raining.$stem$,NULL,$exp$But connects contrasting ideas.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"but","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":1},{"label":"B","body":"under","is_correct":false,"misconception":"Chose a word that does not connect clauses correctly.","misconception_tag":"conjunction_use","sort_order":2},{"label":"C","body":"quickly","is_correct":false,"misconception":"Chose a word that does not connect clauses correctly.","misconception_tag":"conjunction_use","sort_order":3},{"label":"D","body":"because of","is_correct":false,"misconception":"Chose a word that does not connect clauses correctly.","misconception_tag":"conjunction_use","sort_order":4}]$choices$::jsonb),
(10,$code$4.11D.viii$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Choose the best conjunction: We stayed inside ___ the storm passed.$stem$,NULL,$exp$Until shows when the staying ended.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"but","is_correct":false,"misconception":"Chose a conjunction that changes the time relationship.","misconception_tag":"conjunction_use","sort_order":1},{"label":"B","body":"until","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":2},{"label":"C","body":"and","is_correct":false,"misconception":"Chose a conjunction that changes the time relationship.","misconception_tag":"conjunction_use","sort_order":3},{"label":"D","body":"or","is_correct":false,"misconception":"Chose a conjunction that changes the time relationship.","misconception_tag":"conjunction_use","sort_order":4}]$choices$::jsonb),
(11,$code$4.11D.viii$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which sentence uses a coordinating conjunction correctly?$stem$,NULL,$exp$And correctly joins two complete thoughts.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"Maya packed a snack, under Liam filled the bottles.","is_correct":false,"misconception":"Used the wrong conjunction for a compound sentence.","misconception_tag":"conjunction_use","sort_order":1},{"label":"B","body":"Maya packed a snack, although and Liam filled the bottles.","is_correct":false,"misconception":"Used the wrong conjunction for a compound sentence.","misconception_tag":"conjunction_use","sort_order":2},{"label":"C","body":"Maya packed a snack, and Liam filled the bottles.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":3},{"label":"D","body":"Maya packed a snack, because Liam filled the bottles.","is_correct":false,"misconception":"Used the wrong conjunction for a compound sentence.","misconception_tag":"conjunction_use","sort_order":4}]$choices$::jsonb),
(12,$code$4.11D.viii$code$,'211_220'::map_rit_band,'hard'::map_difficulty,$stem$Choose the best subordinating conjunction: ___ it was late, we finished reading.$stem$,NULL,$exp$Although introduces a contrast in a dependent clause.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"And","is_correct":false,"misconception":"Used a coordinating conjunction where a subordinating one is needed.","misconception_tag":"conjunction_use","sort_order":1},{"label":"B","body":"Or","is_correct":false,"misconception":"Used a coordinating conjunction where a subordinating one is needed.","misconception_tag":"conjunction_use","sort_order":2},{"label":"C","body":"But","is_correct":false,"misconception":"Used a coordinating conjunction where a subordinating one is needed.","misconception_tag":"conjunction_use","sort_order":3},{"label":"D","body":"Although","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":4}]$choices$::jsonb),
(13,$code$4.11D.ix$code$,'191_200'::map_rit_band,'easy'::map_difficulty,$stem$Which sentence uses capitalization correctly?$stem$,NULL,$exp$Texas Capitol is a proper noun and the sentence begins with a capital.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"We visited the Texas Capitol.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":1},{"label":"B","body":"We visited the texas Capitol.","is_correct":false,"misconception":"Missed capitalization of a proper noun or sentence beginning.","misconception_tag":"capitalization_rules","sort_order":2},{"label":"C","body":"We visited the Texas capitol.","is_correct":false,"misconception":"Missed capitalization of a proper noun or sentence beginning.","misconception_tag":"capitalization_rules","sort_order":3},{"label":"D","body":"we visited the Texas Capitol.","is_correct":false,"misconception":"Missed capitalization of a proper noun or sentence beginning.","misconception_tag":"capitalization_rules","sort_order":4}]$choices$::jsonb),
(14,$code$4.11D.ix$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which title is capitalized correctly?$stem$,NULL,$exp$Capitalize important words and proper nouns in a title.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"The History Of The Alamo","is_correct":false,"misconception":"Capitalized too much or too little.","misconception_tag":"capitalization_rules","sort_order":1},{"label":"B","body":"The History of the Alamo","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":2},{"label":"C","body":"the History of the Alamo","is_correct":false,"misconception":"Capitalized too much or too little.","misconception_tag":"capitalization_rules","sort_order":3},{"label":"D","body":"The history of the alamo","is_correct":false,"misconception":"Capitalized too much or too little.","misconception_tag":"capitalization_rules","sort_order":4}]$choices$::jsonb),
(15,$code$4.11D.ix$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Choose the correct sentence.$stem$,NULL,$exp$Languages and names are capitalized.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"Hana speaks English and spanish.","is_correct":false,"misconception":"Did not capitalize languages or names.","misconception_tag":"capitalization_rules","sort_order":1},{"label":"B","body":"hana speaks English and Spanish.","is_correct":false,"misconception":"Did not capitalize languages or names.","misconception_tag":"capitalization_rules","sort_order":2},{"label":"C","body":"Hana speaks English and Spanish.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":3},{"label":"D","body":"Hana speaks english and Spanish.","is_correct":false,"misconception":"Did not capitalize languages or names.","misconception_tag":"capitalization_rules","sort_order":4}]$choices$::jsonb),
(16,$code$4.11D.ix$code$,'211_220'::map_rit_band,'hard'::map_difficulty,$stem$Which sentence uses capitalization correctly?$stem$,NULL,$exp$Historical documents and sentence beginnings need capitals.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"The class read the declaration of Independence.","is_correct":false,"misconception":"Missed capitalization in a historical document title.","misconception_tag":"capitalization_rules","sort_order":1},{"label":"B","body":"The class read the Declaration of independence.","is_correct":false,"misconception":"Missed capitalization in a historical document title.","misconception_tag":"capitalization_rules","sort_order":2},{"label":"C","body":"the class read the Declaration of Independence.","is_correct":false,"misconception":"Missed capitalization in a historical document title.","misconception_tag":"capitalization_rules","sort_order":3},{"label":"D","body":"The class read the Declaration of Independence.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":4}]$choices$::jsonb),
(17,$code$4.11D.ix$code$,'221_230'::map_rit_band,'hard'::map_difficulty,$stem$Which revision fixes all capitalization errors?$stem$,NULL,$exp$Months and historical events are capitalized.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"In April, we studied the Battle of San Jacinto.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":1},{"label":"B","body":"In april, we studied the Battle of san Jacinto.","is_correct":false,"misconception":"Did not capitalize a month or historical event.","misconception_tag":"capitalization_rules","sort_order":2},{"label":"C","body":"in April, we studied the battle of San Jacinto.","is_correct":false,"misconception":"Did not capitalize a month or historical event.","misconception_tag":"capitalization_rules","sort_order":3},{"label":"D","body":"In April, we studied the battle of san jacinto.","is_correct":false,"misconception":"Did not capitalize a month or historical event.","misconception_tag":"capitalization_rules","sort_order":4}]$choices$::jsonb),
(18,$code$4.11D.x$code$,'191_200'::map_rit_band,'easy'::map_difficulty,$stem$Which sentence uses quotation marks correctly?$stem$,NULL,$exp$Quotation marks go around the exact words spoken.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"\"Maya said, I found it.\"","is_correct":false,"misconception":"Placed quotation marks incorrectly or omitted them.","misconception_tag":"punctuation_rules","sort_order":1},{"label":"B","body":"Maya said, \"I found it.\"","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":2},{"label":"C","body":"Maya said, I found it.","is_correct":false,"misconception":"Placed quotation marks incorrectly or omitted them.","misconception_tag":"punctuation_rules","sort_order":3},{"label":"D","body":"Maya said, \"I found it.","is_correct":false,"misconception":"Placed quotation marks incorrectly or omitted them.","misconception_tag":"punctuation_rules","sort_order":4}]$choices$::jsonb),
(19,$code$4.11D.x$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Choose the sentence with commas in a series.$stem$,NULL,$exp$Commas separate items in a series.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"We packed pencils, paper and, markers.","is_correct":false,"misconception":"Misplaced commas in a list.","misconception_tag":"punctuation_rules","sort_order":1},{"label":"B","body":"We packed, pencils paper and markers.","is_correct":false,"misconception":"Misplaced commas in a list.","misconception_tag":"punctuation_rules","sort_order":2},{"label":"C","body":"We packed pencils, paper, and markers.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":3},{"label":"D","body":"We packed pencils paper, and markers.","is_correct":false,"misconception":"Misplaced commas in a list.","misconception_tag":"punctuation_rules","sort_order":4}]$choices$::jsonb),
(20,$code$4.11D.x$code$,'201_210'::map_rit_band,'medium'::map_difficulty,$stem$Which sentence uses an apostrophe correctly?$stem$,NULL,$exp$Girl's shows one girl owns the bike.$exp$,$src$Original Grade 4 language usage seed: 2026-04-30$src$,$choices$[{"label":"A","body":"The girls bike is red.","is_correct":false,"misconception":"Confused possessive apostrophe placement.","misconception_tag":"punctuation_rules","sort_order":1},{"label":"B","body":"The girls's bike is red.","is_correct":false,"misconception":"Confused possessive apostrophe placement.","misconception_tag":"punctuation_rules","sort_order":2},{"label":"C","body":"The girl bike's is red.","is_correct":false,"misconception":"Confused possessive apostrophe placement.","misconception_tag":"punctuation_rules","sort_order":3},{"label":"D","body":"The girl's bike is red.","is_correct":true,"misconception":null,"misconception_tag":null,"sort_order":4}]$choices$::jsonb)
), ins as (
  insert into map_questions(subject,grade,standard_id,passage_id,rit_band,difficulty,stem,stem_image_svg,audio_supported,explanation,source_note,is_active,question_format)
  select 'language'::map_subject,4,s.id,null,seed.rit_band,seed.difficulty,seed.stem,seed.stem_image_svg,true,seed.explanation,seed.source_note,true,'mcq'
  from seed
  join map_standards s on s.grade=4 and s.subject='language'::map_subject and s.teks_code=seed.teks_code
  where not exists (
    select 1 from map_questions q
    where q.grade=4 and q.subject='language'::map_subject and q.source_note=seed.source_note and q.stem=seed.stem and q.explanation=seed.explanation
  )
  returning id, stem, explanation, source_note
)
insert into map_question_choices(question_id,label,body,body_image_svg,is_correct,misconception,misconception_tag,sort_order)
select ins.id,c.label,c.body,null,c.is_correct,c.misconception,c.misconception_tag,c.sort_order
from ins
join seed on seed.stem=ins.stem and seed.explanation=ins.explanation and seed.source_note=ins.source_note
cross join lateral jsonb_to_recordset(seed.choices) as c(label char(1), body text, is_correct boolean, misconception text, misconception_tag text, sort_order smallint);